ll prea[N], preb[N];
void solve(int CASE)
{
	ll n; cin >> n;
	string a, b; cin >> a >> b; a = ' ' + a, b = ' ' + b;
	fa(i, 1, n) {
		prea[i] = prea[i - 1] + (a[i] == '1');
		preb[i] = preb[i - 1] + (b[i] == '1');
	}

	//fa(i, 1, n) 
	//	fa(j, 1, n) 
	//		ans += min(prea[i] + preb[j], i - prea[i] + j - preb[j]);
	// 
	// min(X, Y) = (X + Y - |X - Y|) / 2
	// X + Y = i + j
	// X - Y = (2 ⋅ prea[i] − i) + (2 ⋅ preb[j] − j)
	// 设 f(i) = (2 ⋅ prea[i] − i)，g(j) = (2 ⋅ preb[j] − j)
	// 求    sum_{i,j} |f(i) + g(j)|
	//    => sum_{i,j} |f(i) - (-g(j))|

	ll ans = n * n * (n + 1) / 2;

	var f = vector<ll>(n + 1);
	var g = vector<ll>(n + 1);
	ll totg = 0;
	fa(i, 1, n) {
		f[i] = 2 * prea[i] - i;
		g[i] = -(2 * preb[i] - i);
		totg += g[i];
	}
	sort(all1(f)), sort(all1(g));

	ll res = 0;
	ll j = 0, preg = 0;
	fa(i, 1, n) {
		while (j + 1 <= n and g[j + 1] < f[i]) {
			j++;
			preg += g[j];
		}
		res += f[i] * j - preg;
		res += (totg - preg) - f[i] * (n - j);
	}
	res /= 2;

	cout << ans - res << endl;
	return;
}
